package com.careeros.provider.domain;

import com.careeros.common.domain.AuditableEntity;import com.careeros.company.domain.Company;import jakarta.persistence.*;import org.hibernate.annotations.UuidGenerator;import java.time.Instant;import java.util.UUID;
@Entity @Table(name="sync_history") public class SyncHistory extends AuditableEntity{@Id @UuidGenerator private UUID id;@ManyToOne(fetch=FetchType.EAGER,optional=false)@JoinColumn(name="company_id")private Company company;@Enumerated(EnumType.STRING)@Column(nullable=false)private ProviderType provider;@Column(nullable=false)private Instant startedAt;@Column(nullable=false)private Instant completedAt;@Column(nullable=false)private long durationMs;@Column(nullable=false)private boolean success;@Column(nullable=false)private int jobsFound;@Column(nullable=false)private int jobsAdded;@Column(nullable=false)private int jobsUpdated;@Column(length=2000)private String errorMessage;protected SyncHistory(){}public static SyncHistory record(Company c,ProviderType p,Instant start,boolean success,int found,int added,int updated,String error){var h=new SyncHistory();h.company=c;h.provider=p;h.startedAt=start;h.completedAt=Instant.now();h.durationMs=Math.max(0,java.time.Duration.between(start,h.completedAt).toMillis());h.success=success;h.jobsFound=found;h.jobsAdded=added;h.jobsUpdated=updated;h.errorMessage=error;return h;}public UUID getId(){return id;}public Company getCompany(){return company;}public ProviderType getProvider(){return provider;}public Instant getStartedAt(){return startedAt;}public Instant getCompletedAt(){return completedAt;}public long getDurationMs(){return durationMs;}public boolean isSuccess(){return success;}public int getJobsFound(){return jobsFound;}public int getJobsAdded(){return jobsAdded;}public int getJobsUpdated(){return jobsUpdated;}public String getErrorMessage(){return errorMessage;}}
